#include <iostream>
#include <cmath>

bool isPerfect(int num) {
    if (num <= 1) {
        return false;
    }

    long long sumOfDivisors = 1;

    for (int i = 2; i * i <= num; ++i) {
        if (num % i == 0) {
            sumOfDivisors += i;
            if (i * i != num) {
                sumOfDivisors += (num / i);
            }
        }
    }
    return sumOfDivisors == num;
}

int main() {
    std::cout << "isPerfect(6): " << (isPerfect(6) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(28): " << (isPerfect(28) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(496): " << (isPerfect(496) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(8128): " << (isPerfect(8128) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(1): " << (isPerfect(1) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(0): " << (isPerfect(0) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(-5): " << (isPerfect(-5) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(7): " << (isPerfect(7) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(12): " << (isPerfect(12) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(25): " << (isPerfect(25) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(30): " << (isPerfect(30) ? "true" : "false") << std::endl;
    std::cout << "isPerfect(33550336): " << (isPerfect(33550336) ? "true" : "false") << std::endl;
    return 0;
}
